using System.Windows.Forms; namespace btlwindow { public static class NavigationManager { private static Panel mainPanel; public static void Initialize(Panel panel) { mainPanel = panel; } public static void ShowControl(UserControl control) { if (mainPanel == null) return; mainPanel.Controls.Clear(); control.Dock = DockStyle.Fill; mainPanel.Controls.Add(control); } public static void ClearPanel() { if (mainPanel != null) mainPanel.Controls.Clear(); } } }